import json
from openai import OpenAI

client = OpenAI()

response = client.chat.completions.create(
    model="gpt-4o-mini",
    response_format={"type": "json_object"},
    messages=[
        {
            "role": "system",
            "content": (
                "Extract information from the text and return JSON with exactly these keys: "
                '"name" (string), "age" (integer), "city" (string). '
                'If a field is not mentioned, use null.'
            ),
        },
        {
            "role": "user",
            "content": "Alice is 30 years old and lives in Berlin.",
        },
    ],
)

data = json.loads(response.choices[0].message.content)
print(data)
# → {'name': 'Alice', 'age': 30, 'city': 'Berlin'}
print(data["name"])  # 'Alice'

import json
from pydantic import BaseModel, ValidationError
from openai import OpenAI
from typing import Optional

client = OpenAI()


class PersonInfo(BaseModel):
    name: str
    age: int
    city: Optional[str] = None


def extract_person(text: str) -> PersonInfo:
    response = client.chat.completions.create(
        model="gpt-4o-mini",
        response_format={"type": "json_object"},
        messages=[
            {
                "role": "system",
                "content": (
                    'Return JSON with keys "name" (string), "age" (integer), '
                    '"city" (string or null).'
                ),
            },
            {"role": "user", "content": text},
        ],
    )
    raw = json.loads(response.choices[0].message.content)
    try:
        return PersonInfo(**raw)
    except ValidationError as e:
        raise ValueError(f"LLM returned invalid structure: {e}") from e


person = extract_person("Bob is 25 and works in London.")
print(person.name, person.age, person.city)  # Bob 25 London
